mapper.sql:
SELECT
	  ROW_NUMBER() OVER(ORDER BY SMNR_ID, USER_ID) AS lineNo
	, SEMINAR_REG_ID	AS seminarRegId
	, SMNR_ID		AS seminarId
	, SBJCT_ID        AS crsCreCd
	, ZOOM_ID           AS zoomId
	, STD_ID            AS stdNo
	, USER_ID           AS userId
	, PREREG_ID      AS registantId
	, PTCP_URL          AS joinUrl
	, TKN_EML          AS tcEmail
	, RGTR_ID            AS rgtrId
	, FRST_INQ_DTTM          AS regDttm
  FROM TB_LMS_SMNR_PREREG
 WHERE 1 = 1

   AND SEMINAR_REG_ID = #{seminarRegId}


   AND SMNR_ID = #{seminarId}


   AND SBJCT_ID = #{crsCreCd}


   AND ZOOM_ID = #{zoomId}


   AND STD_ID = #{stdNo}


   AND USER_ID = #{userId}


   AND PREREG_ID = #{registantId}


   AND TKN_EML = #{tcEmail}

mapper.insert:
		/*
             SQL ID : SeminarRegDAO.insert
            	 설  명 : 세미나 사전 등록 참가자 등록
         */
         INSERT INTO TB_LMS_SMNR_PREREG (
         	  SEMINAR_REG_ID
         	, SMNR_ID
			, SBJCT_ID
			, ZOOM_ID
			, STD_ID
			, USER_ID
			, PREREG_ID
			, PTCP_URL
			, TKN_EML
			, RGTR_ID
			, FRST_INQ_DTTM
         ) VALUES (
         	  #{seminarRegId}
         	, #{seminarId}
         	, #{crsCreCd}
         	, #{zoomId}
         	, #{stdNo}
         	, #{userId}
         	, #{registantId}
         	, #{joinUrl}
         	, #{tcEmail}
         	, #{rgtrId}
         	, FN_DTTM()
         )

mapper.update:
		/*
             SQL ID : SeminarRegDAO.update
            	 설  명 : 세미나 사전 등록 참가자 수정
         */
         UPDATE TB_LMS_SMNR_PREREG SET
         	    SMNR_ID = #{seminarId}

         	  , PREREG_ID = #{registantId}


         	  , PTCP_URL = #{joinUrl}


         	  , TKN_EML = #{tcEmail}

          WHERE ZOOM_ID = #{zoomId}

            AND SEMINAR_REG_ID = #{seminarRegId}


            AND STD_ID = #{stdNo}

mapper.delete:
		/*
             SQL ID : SeminarRegDAO.delete
            	 설  명 : 세미나 사전 등록 참가자 삭제
         */
         DELETE FROM TB_LMS_SMNR_PREREG
          WHERE ZOOM_ID = #{zoomId}

          	AND SEMINAR_REG_ID = #{seminarRegId}


            AND USER_ID = #{userId}


            AND STD_ID = #{stdNo}


          	AND PREREG_ID = #{registantId}


            AND SMNR_ID = #{seminarId}
